RewardUtil = {}

function RewardUtil:tryConsumeRewards(player)
    if not DbUtil:IsGetAllDataFinished(player) then
        return
    end
    for _, reward in pairs(player.rewards) do
        if reward.Type == RewardUtil.RewardType.CARD_TIMES then
            RewardUtil:addPlayerCardWithTimes(player, reward.Id, reward.Count)
        end
        if reward.Type == RewardUtil.RewardType.CARD_TIME then
            RewardUtil:addPlayerCardWithTime(player, reward.Id, reward.Count)
        end
        if reward.Type == RewardUtil.RewardType.PROP then
            RewardUtil:addPlayerProp(player, reward.Id, reward.Count)
        end
    end
    player.rewards = {}
end

function RewardUtil:doReward(player, reward)
    if not reward then
        return false
    end

    if reward.RewardType == Define.RewardType.CARD_TIMES then
        self:addPlayerCardWithTimes(player, reward.RewardId, reward.Count)

    elseif reward.RewardType == Define.RewardType.PROP then
        self:addPlayerProp(player, reward.RewardId, reward.Count)
    end

    return reward.Id
end

function RewardUtil:addPlayerCardWithTimes(player, id, times)
    player.GameJob:updateJobUIData(id, times)
end

function RewardUtil:addPlayerCardWithTime(player, id, time)

end

function RewardUtil:addPlayerProp(player, id, num)
    player.init_prop = {}

    local item = {
        id = id,
        num = num
    }
    table.insert(player.init_prop, item)
    GamePacketSender:sendUsePropData(player.rakssid, id, num)
end

return RewardUtil